import { inject } from '@angular/core';
import { from, Observable, throwError } from 'rxjs';
import { map, catchError } from 'rxjs/operators';
import { TimbratureSupabaseService } from './timbrature-supabase.service';
import { SupabaseClient } from '@supabase/supabase-js';

export abstract class BaseService<T> {
  protected supabase: SupabaseClient;
  protected abstract tableName: string;

  constructor() {
    this.supabase = inject(TimbratureSupabaseService).getSupabaseClient();
  }

  getAll(companyId?: string, options?: { orderBy?: string; ascending?: boolean }): Observable<T[]> {
    let query = this.supabase.from(this.tableName).select('*');
    if (companyId) query = query.eq('company_id', companyId);
    if (options?.orderBy) query = query.order(options.orderBy, { ascending: options.ascending ?? true });
    return from(query).pipe(
      map(result => result.data as T[]),
      catchError(error => throwError(() => error))
    );
  }

  getById(id: string, companyId?: string): Observable<T | null> {
    let query = this.supabase.from(this.tableName).select('*').eq('id', id);
    if (companyId) query = query.eq('company_id', companyId);
    return from(query.maybeSingle()).pipe(
      map(result => result.data as T | null),
      catchError(error => throwError(() => error))
    );
  }

  create(item: Partial<T>): Observable<T> {
    return from(this.supabase.from(this.tableName).insert(item).select().single()).pipe(
      map(result => result.data as T),
      catchError(error => throwError(() => error))
    );
  }

  update(id: string, updates: Partial<T>, companyId?: string): Observable<T> {
    let query = this.supabase.from(this.tableName).update(updates).eq('id', id);
    if (companyId) query = query.eq('company_id', companyId);
    return from(query.select().single()).pipe(
      map(result => result.data as T),
      catchError(error => throwError(() => error))
    );
  }

  delete(id: string, companyId?: string): Observable<void> {
    let query = this.supabase.from(this.tableName).delete().eq('id', id);
    if (companyId) query = query.eq('company_id', companyId);
    return from(query).pipe(
      map(() => {}),
      catchError(error => throwError(() => error))
    );
  }

  softDelete(id: string, deletedBy: string, companyId?: string): Observable<void> {
    const updates = {
      deleted: true,
      deleted_at: new Date().toISOString(),
      deleted_by: deletedBy
    };
    let query = this.supabase.from(this.tableName).update(updates).eq('id', id);
    if (companyId) query = query.eq('company_id', companyId);
    return from(query).pipe(
      map(() => {}),
      catchError(error => throwError(() => error))
    );
  }

  restore(id: string, companyId?: string): Observable<void> {
    const updates = {
      deleted: false,
      deleted_at: null,
      deleted_by: null
    };
    let query = this.supabase.from(this.tableName).update(updates).eq('id', id);
    if (companyId) query = query.eq('company_id', companyId);
    return from(query).pipe(
      map(() => {}),
      catchError(error => throwError(() => error))
    );
  }
  
}