import { Injectable, inject } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { Router } from '@angular/router';
import { AuthService as PlateaAuthService } from '../../services/Base/auth.service';
import { HttpHeaders } from '@angular/common/http';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private plateaAuth = inject(PlateaAuthService);
  private router = inject(Router);

  // ── Stessa interfaccia che si aspettano i componenti Timbrature ──

  get currentUser$() {
    return this.plateaAuth.currentUser$;
  }

  get currentUserSubject() {
    return this.plateaAuth.currentUserSubject;
  }

  get sidebarCollapsed$() {
    return this.plateaAuth.sidebarCollapsed$;
  }

  isAuthenticated(): boolean {
    return this.plateaAuth.isAuthenticated();
  }

  // Mappa i ruoli di Platea → ruoli di Timbrature
  // owner/manager → admin | tutti gli altri staff → employee
  hasRole(role: string): boolean {
    const staffRole = this.plateaAuth.getStaffRole();
    const isOwner = this.plateaAuth.isOwner();
    if (role === 'admin') return isOwner || staffRole === 'manager';
    if (role === 'manager') return staffRole === 'manager';
    if (role === 'employee') return !!staffRole || isOwner;
    return false;
  }

  async hasManagerPermission(
    permission: 'manage_departments' | 'view_all_employees',
    companyId?: string
  ): Promise<boolean> {
    const isOwner = this.plateaAuth.isOwner();
    if (isOwner) return true;
    const staffRole = this.plateaAuth.getStaffRole();
    if (staffRole === 'manager') return true;
    return false;
  }

  async getToken(): Promise<string | null> {
    const supabase = (this.plateaAuth as any).supabaseService;
    if (!supabase) return null;
    try {
      const { data } = await supabase.getSession();
      return data?.session?.access_token ?? null;
    } catch {
      return null;
    }
  }

  // company_id nel contesto Timbrature corrisponde a restaurant_id in Platea
  // I componenti Timbrature usano currentUser$.company_id
  // quindi mappiamo currentUser$ aggiungendo company_id = activeRestaurantId
  get currentUserWithCompany$() {
    return new BehaviorSubject({
      ...this.plateaAuth.currentUserValue,
      company_id: this.plateaAuth.getCurrentRestaurantId()
    }).asObservable();
  }

  // Metodo usato da AuthService di Timbrature per aggiornare utente esterno
  setExternalUser(user: any) {
    // no-op: in Platea l'utente è gestito da PlateaAuthService
  }

  toggleSidebar() {
    this.plateaAuth.toggleSidebar();
  }

  setSidebarCollapsed(collapsed: boolean) {
    this.plateaAuth.setSidebarCollapsed(collapsed);
  }

  getSidebarCollapsedValue(): boolean {
    return this.plateaAuth.getSidebarCollapsed();
  }

  // Logout — reindirizza al login di Platea
  async logout(): Promise<void> {
    await this.plateaAuth.logout();
  }

get companyId(): string | null {
  return this.plateaAuth.getCurrentRestaurantId();
}

getAuthHeaders(): HttpHeaders {
  // In Platea l'auth è gestita da Supabase direttamente
  // questi metodi REST non vengono usati nell'integrazione
  // ma servono per non rompere la compilazione
  return new HttpHeaders({
    'Content-Type': 'application/json'
  });
}

async updateUserProfile(userId: string, patch: any): Promise<any> {
  const { data, error } = await this.plateaAuth['supabaseService']
    .getSupabaseClient()
    .from('users')
    .update(patch)
    .eq('id', userId)
    .select()
    .single();
  if (error) throw error;
  return data;
}

}